const escapeXml = (value: string) =>
  value
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");

export default async function jsonToXmlPolicy(request: Request): Promise<Request | Response> {
  let payload: unknown;

  try {
    payload = await request.json();
  } catch (error) {
    return new Response("Invalid JSON body", { status: 400 });
  }

  if (typeof payload !== "object" || payload === null || !("user" in payload)) {
    return new Response("Missing user payload", { status: 400 });
  }

  const user = (payload as { user: { name?: string; role?: string } }).user;
  const name = escapeXml(String(user?.name ?? ""));
  const role = escapeXml(String(user?.role ?? ""));
  const xmlBody = `<user><name>${name}</name><role>${role}</role></user>`;

  const headers = new Headers(request.headers);
  headers.set("content-type", "application/xml");

  return new Request(request.url, {
    method: request.method,
    headers,
    body: xmlBody,
    redirect: request.redirect
  });
}

export default async function echoHandler(request: Request): Promise<Response> {
  const body = await request.text();

  return new Response(body, {
    status: 200,
    headers: {
      "content-type": "text/plain"
    }
  });
}
